// Filter: Nur aktive Mieten (Aktiv, Verlängert, unbefristet)
const items = $input.all();
const result = [];
const activeStatuses = ['Aktiv', 'Verlängert', 'unbefristet'];

for (const item of items) {
  const status = item.json.Status?.value;
  if (activeStatuses.includes(status)) {
    result.push(item);
  }
}

return result;

// Berechne welche E-Mails heute fällig sind
const items = $input.all();
const result = [];
const heute = new Date();
heute.setHours(0, 0, 0, 0);

for (const item of items) {
  const mietbeginn = item.json.Mietbeginn;
  const mietendeBerechnet = item.json.Mietende_berechnet;
  const mietId = item.json.id;
  const kundeId = item.json.Kunde_ID?.[0]?.id;
  const instrumentId = item.json.Instrument_ID?.[0]?.id;

  if (!kundeId) continue;

  // Woche 1: Mietbeginn + 7 Tage
  if (mietbeginn) {
    const woche1 = new Date(mietbeginn);
    woche1.setDate(woche1.getDate() + 7);
    woche1.setHours(0, 0, 0, 0);
    if (heute.getTime() === woche1.getTime()) {
      result.push({
        json: {
          ...item.json,
          _emailType: 'Woche 1',
          _emailTypeId: 3118,
          _kundeId: kundeId,
          _instrumentId: instrumentId,
          _mietId: mietId
        }
      });
    }
  }

  // Pre_end_14d: Mietende - 14 Tage
  if (mietendeBerechnet) {
    const pre14 = new Date(mietendeBerechnet);
    pre14.setDate(pre14.getDate() - 14);
    pre14.setHours(0, 0, 0, 0);
    if (heute.getTime() === pre14.getTime()) {
      result.push({
        json: {
          ...item.json,
          _emailType: 'Pre_end_14d',
          _emailTypeId: 3120,
          _kundeId: kundeId,
          _instrumentId: instrumentId,
          _mietId: mietId
        }
      });
    }
  }

  // Pre_end_2d: Mietende - 2 Tage
  if (mietendeBerechnet) {
    const pre2 = new Date(mietendeBerechnet);
    pre2.setDate(pre2.getDate() - 2);
    pre2.setHours(0, 0, 0, 0);
    if (heute.getTime() === pre2.getTime()) {
      result.push({
        json: {
          ...item.json,
          _emailType: 'Pre_end_2d',
          _emailTypeId: 3121,
          _kundeId: kundeId,
          _instrumentId: instrumentId,
          _mietId: mietId
        }
      });
    }
  }
}

return result;

// Erstelle E-Mail basierend auf Typ
const items = $input.all();
const result = [];
const GOOGLE_BEWERTUNGS_LINK = 'GOOGLE_BEWERTUNGS_LINK_HIER_EINTRAGEN';

for (const item of items) {
  const emailType = item.json._emailType;
  const vorname = item.json.Vorname || 'Kunde';
  const nachname = item.json.Nachname || '';
  const instrumentName = item.json.Modellname || 'Instrument';
  const mietendeRaw = item.json.Mietende_berechnet;
  const mietende = mietendeRaw ? new Date(mietendeRaw).toLocaleDateString('de-DE') : '–';
  const mietkaufpreis = item.json.Mietkaufpreis?.[0]?.value || '–';

  let subject = '';
  let body = '';

  if (emailType === 'Woche 1') {
    subject = `Check-in: ${vorname} ${nachname} – ${instrumentName} (1 Woche)`;
    body = `Hallo ${vorname},\n\ndas Set steht jetzt eine Woche bei dir. Ich wollte kurz nachfragen, ob alles passt und du gut zurechtkommst.\n\nFalls irgendwas nicht funktioniert oder du Fragen hast, melde dich einfach.\n\nWenn du zufrieden bist, würde ich mich über eine kurze Google-Bewertung freuen. Das hilft mir sehr und dauert nur eine Minute:\n${GOOGLE_BEWERTUNGS_LINK}\n\nViele Grüße\nManuel`;
  } else if (emailType === 'Pre_end_14d') {
    subject = `Mietende in 14 Tagen: ${vorname} ${nachname} – ${instrumentName}`;
    body = `Hallo ${vorname},\n\nkurze Info: Deine Mietzeit für das ${instrumentName} endet am ${mietende}.\n\nDu hast drei Möglichkeiten:\n- Weitermieten (Laufzeit verlängern)\n- Mietkauf (bisherige Mieten werden angerechnet, Kaufpreis: ${mietkaufpreis} €)\n- Rückgabe\n\nSag mir einfach kurz Bescheid, wie du es machen möchtest. Dann kümmere ich mich um alles Weitere.\n\nViele Grüße\nManuel`;
  } else if (emailType === 'Pre_end_2d') {
    subject = `Mietende übermorgen: ${vorname} ${nachname} – ${instrumentName}`;
    body = `Hallo ${vorname},\n\nnur als kurze Erinnerung: Die Mietzeit für das ${instrumentName} endet am ${mietende}.\n\nFalls du weitermieten oder kaufen möchtest, melde dich bitte zeitnah bei mir, damit wir alles rechtzeitig klären können.\n\nViele Grüße\nManuel`;
  }

  result.push({
    json: {
      ...item.json,
      _subject: subject,
      _body: body
    }
  });
}

return result;
